import{hsvToHex}from"/scripts/applets/applet.min.js";import{createDesmosGraphs,desmosColors,getColored3DCurve,getDesmosSlider}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({parametricCurveShaping:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-1.5,xmax:1.5,ymin:-1.5,ymax:1.5,zmin:-1.5,zmax:1.5},expressions:[{latex:raw`l(t) = (\cos(2t), \sin(2t), t)`,hidden:!0},...getColored3DCurve({pathFunction:t=>[t,0,0],pathFunctionDesmos:raw`(1 - s) (1, 0, 0)t + s l(6(t-0.5))`,minT:0,maxT:1,numSlices:100,colorFunction:([x])=>hsvToHex(1-.5*x,1,1)}),...getDesmosSlider({expression:"s = 0",min:0,max:1,secret:!1})]},parametricSurfaceShaping:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-1.5,xmax:1.5,ymin:-1.5,ymax:1.5,zmin:-1.5,zmax:1.5},expressions:[{latex:raw`X(u) = \tan(\pi (u - \frac{1}{2}))`,hidden:!0,secret:!1},{latex:raw`Y(v) = \tan(\pi (v - \frac{1}{2}))`,hidden:!0,secret:!1},{latex:raw`c(u, v) = \frac{1}{1 + X(u)^2 + Y(v)^2}(2X(u), 2Y(v), -1 + X(u)^2 + Y(v)^2)`,hidden:!0,secret:!1},{latex:raw`(1 - s) (u, v, 0) + s c(u, v)`,colorLatex:"C",secret:!0},{latex:raw`U(x, y, z) = s\frac{1}{2} + \frac{4 - 3s}{\pi}\arctan(\frac{x}{1 - z})`,secret:!0},{latex:raw`V(x, y, z) = s\frac{1}{2} + \frac{4 - 3s}{\pi}\arctan(\frac{y}{1 - z})`,secret:!0},...getDesmosSlider({expression:"s = 0",min:0,max:1,secret:!1}),{latex:raw`C = \operatorname{rgb}(255\left|U(x, y, z)\right|^{1.3151}, 255\left|V(x, y, z)\right|^{1.3151}, 255)`,secret:!0}]},parametricSurface:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-1.5,xmax:1.5,ymin:-1.5,ymax:1.5,zmin:-1.5,zmax:1.5},expressions:[{latex:raw`s(u, v) = (v, \cos(u), \sin(u))`},{latex:raw`s(u, v)`,parametricDomain3Du:{min:0,max:"2\\pi"},parametricDomain3Dv:{min:-1,max:1},color:desmosColors.purple},{latex:raw`U = [0, \frac{\pi}{4}, ..., 2\pi]`},{latex:raw`V = [-1, -0.5, ..., 1]`},{latex:raw`s(t, V)`,parametricDomain:{min:0,max:"2\\pi"},color:desmosColors.blue},{latex:raw`s(U, t)`,parametricDomain:{min:-1,max:1},color:desmosColors.red}]},doubleCone:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-2.5,xmax:2.5,ymin:-2.5,ymax:2.5,zmin:-2.5,zmax:2.5},expressions:[{latex:raw`(v\cos(u), v\sin(u), v)`,parametricDomain3Du:{min:0,max:"2\\pi"},parametricDomain3Dv:{min:-2,max:2},color:desmosColors.purple,secret:!0}]},functionParameterization:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-7.5,xmax:7.5,ymin:-7.5,ymax:7.5,zmin:-7.5,zmax:7.5},expressions:[{latex:raw`(u, v, u\cos(v))`,parametricDomain3Du:{min:"-2\\pi",max:"2\\pi"},parametricDomain3Dv:{min:"-2\\pi",max:"2\\pi"},color:desmosColors.purple,secret:!0}]}})}